/*
 * ilogb() test harness -- prints (input_hex, output_int) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile int g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += ilogb(vx);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    int r = ilogb(x);
    printf("%016llx %d\n", (unsigned long long)d2u(x), r);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit_u(0x0010000000000000ULL);  /* DBL_MIN = 2^-1022, ilogb = -1022 */
    emit_u(0x8010000000000000ULL);  /* -DBL_MIN */
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX, ilogb = 1023 */
    emit_u(0xffefffffffffffffULL);  /* -DBL_MAX */
    emit_u(0x7feffffffffffff0ULL);  /* a few ULPs below DBL_MAX */

    /* --- Section 4: Near 1.0 -- highest ULP density for normal inputs (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0, ilogb = -1 */
    emit(1.0);                      /* 1.0, ilogb = 0 */
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0, ilogb = 0 */
    emit_u(0x3fefffffffffff00ULL);  /* a few ULPs below 1.0, ilogb = -1 */
    emit_u(0x3ff0000000000010ULL);  /* a few ULPs above 1.0, ilogb = 0 */
    emit(-1.0);                     /* -1.0, ilogb = 0 */
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0, ilogb = -1 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0, ilogb = 0 */

    /* --- Section 5: Powers of 2 -- exponent switching boundaries (14) --- */
    emit(0.125);    /* 2^-3, ilogb = -3 */
    emit(-0.125);
    emit(0.25);     /* 2^-2, ilogb = -2 */
    emit(-0.25);
    emit(0.5);      /* 2^-1, ilogb = -1 */
    emit(-0.5);
    emit(2.0);      /* 2^1, ilogb = 1 */
    emit(-2.0);
    emit(4.0);      /* 2^2, ilogb = 2 */
    emit(-4.0);
    emit(8.0);      /* 2^3, ilogb = 3 */
    emit(-8.0);
    emit(1024.0);   /* 2^10, ilogb = 10 */
    emit(-1024.0);

    /* --- Section 6: ULP neighbors of exponent boundaries (12) --- */
    emit_u(0x3fefffffffffffffULL);  /* just below 1.0 = 2^0, ilogb = -1 (dup section 4 skipped: use 2^1) */
    emit_u(0x3ff0000000000000ULL);  /* exactly 2^0 = 1.0, ilogb = 0 */
    emit_u(0x4000000000000000ULL);  /* exactly 2^1 = 2.0, ilogb = 1 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0, ilogb = 0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0, ilogb = 1 */
    emit_u(0x4010000000000000ULL);  /* 2^2 = 4.0, ilogb = 2 */
    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0, ilogb = 1 */
    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0, ilogb = 2 */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 = 2^-1, ilogb = -1 */
    emit_u(0x3fdfffffffffffffULL);  /* one ULP below 0.5, ilogb = -2 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5, ilogb = -1 */
    emit_u(0x3fc0000000000000ULL);  /* 0.125 = 2^-3, ilogb = -3 */

    /* --- Section 7: Non-power-of-2 values across exponent range (18) --- */
    emit(1.5);          /* 3/2, ilogb = 0 */
    emit(-1.5);
    emit(3.0);          /* ilogb = 1 */
    emit(-3.0);
    emit(3.5);          /* 7/2, ilogb = 1 */
    emit(5.0);          /* ilogb = 2 */
    emit(-5.0);
    emit(7.5);          /* 15/2, ilogb = 2 */
    emit(10.0);         /* ilogb = 3 */
    emit(-10.0);
    emit(100.0);        /* ilogb = 6 */
    emit(1000.0);       /* ilogb = 9 */
    emit(3.14159265358979323846);   /* pi, ilogb = 1 */
    emit(-3.14159265358979323846);  /* -pi, ilogb = 1 */
    emit(1.41421356237309504880);   /* sqrt(2), ilogb = 0 */
    emit(2.71828182845904523536);   /* e, ilogb = 1 */
    emit(1.5e-5);       /* ilogb = -17 */
    emit(6.28318530717958647692);   /* 2*pi, ilogb = 2 */

    /* --- Section 8: Large values (11) --- */
    emit(1.0e10);        /* ilogb = 33 */
    emit(-1.0e10);
    emit(1.0e50);        /* ilogb = 166 */
    emit(1.0e100);       /* ilogb = 332 */
    emit(-1.0e100);
    emit(1.0e200);       /* ilogb = 664 */
    emit(-1.0e200);
    emit(1.0e300);       /* ilogb = 996 */
    emit(-1.0e300);
    emit_u(0x7feffffffff00000ULL);  /* near DBL_MAX */
    emit_u(0x7fe0000000000000ULL);  /* 2^1022 */

    /* --- Section 9: Small normal values (12) --- */
    emit(1.0e-10);       /* ilogb = -34 */
    emit(-1.0e-10);
    emit(1.0e-50);       /* ilogb = -167 */
    emit(1.0e-100);      /* ilogb = -333 */
    emit(-1.0e-100);
    emit(1.0e-200);      /* ilogb = -665 */
    emit(-1.0e-200);
    emit(1.0e-300);      /* ilogb = -997 */
    emit(1.0e-307);      /* near subnormal boundary, ilogb = -1021 */
    emit(1.0e-308);      /* DBL_MIN range, ilogb = -1022 */
    emit_u(0x0020000000000000ULL);  /* 2^-1021 */
    emit_u(0x0030000000000000ULL);  /* 1.5 * 2^-1021, ilogb = -1021 */

    /* --- Section 10: Exact exponent-field values across full range (6) --- */
    emit_u(0x0040000000000000ULL);  /* 2^-1019, ilogb = -1019 */
    emit_u(0x4024000000000000ULL);  /* 10.0 exact bits, ilogb = 3 */
    emit_u(0x7fd0000000000000ULL);  /* 2^1021, ilogb = 1021 */
    emit_u(0x0080000000000000ULL);  /* 2^-1018, ilogb = -1018 */
    emit_u(0xc000000000000000ULL);  /* -2.0, ilogb = 1 */
    emit_u(0x4059000000000000ULL);  /* 100.0 exact bits, ilogb = 6 */
}

#ifndef EN_PERF
/* Sweep across exponent boundaries using ldexp */
static void test_sweep(void)
{
    for (int p = -50; p <= 50; p += 5) {
        double scale = ldexp(1.0, p);
        emit(scale);
        emit(-scale);
        emit(1.5 * scale);
        emit(-1.5 * scale);
    }
}
#endif

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %d\n", (int)g_acc);
#else
    test_representative_100();
    test_sweep();
#endif
    return 0;
}
